export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type Result = QuoteResult | ClaimResult;

export interface Output {
  results: Result[];
}

export interface Policy {
  items: Item[];
  insuranceSum: number;
  totalPayoutCap: number;
  usedPayout: number;
}

