    const items: Item[] = [
      { type: 'sword', material: 'steel', enchantment: 3, cursed: false },
    ];
    const customer: Customer = { yearsWithMHPCO: 0 };
    // Base: 100, first insurance: 100 * 1.1 = 110, fee: 110 + 5 = 115
    expect(calculatePremium(items, customer, true)).toBe(115);
