    // Rounded up: 138
    expect(calculatePremium(items, customer, false)).toBe(138);
  });

  it('rounds up in MHPCO favor', () => {
    const items: Item[] = [
      { type: 'sword', material: 'steel', enchantment: 3, cursed: false },
    ];
    const customer: Customer = { yearsWithMHPCO: 0 };
